#!/usr/bin/env bash
# bootstrap.sh — Self-contained CGC Conductor Workflow installer.
# All agent/installer files embedded. No downloads beyond this script.
#
# Usage:
#   curl -fsSL https://raw.githubusercontent.com/cgc-dev/cgc-conductor-workflow/main/bootstrap.sh -o bootstrap.sh && bash bootstrap.sh --tool claude
set -euo pipefail

TOOL=""
TARGET=""

cleanup() { [[ -n "${TEMP_DIR:-}" && -d "$TEMP_DIR" ]] && rm -rf "$TEMP_DIR" || true; }
trap cleanup EXIT

usage() {
  cat << 'USAGE_EOF'
CGC AI Agents -- Bootstrap Installer
Usage: ./bootstrap.sh --tool claude|copilot|cursor|all [--target /path]
USAGE_EOF
  exit 0
}

while [[ $# -gt 0 ]]; do
  case "$1" in
    --tool) TOOL="$2"; shift 2 ;;
    --target) TARGET="$2"; shift 2 ;;
    --help|-h) usage ;;
    *) echo "Unknown: $1"; exit 1 ;;
  esac
done

[[ -n "$TOOL" ]] || {
  echo "Select: 1) Claude 2) Copilot 3) Cursor 4) All"
  read -rp "Choice [1-4]: " c
  case "$c" in 1) TOOL=claude;; 2) TOOL=copilot;; 3) TOOL=cursor;; 4) TOOL=all;; *) exit 1;; esac
}
case "$TOOL" in claude|copilot|cursor|all) ;; *) echo "Invalid: $TOOL"; exit 1;; esac
[[ -n "$TARGET" ]] || TARGET="$PWD"

echo "CGC Conductor Workflow -- Bootstrap Installer"
echo "Tool: $TOOL  Target: $TARGET"
echo ""

TEMP_DIR="$(mktemp -d)"

extract() {
  local path="$1" b64="$2"
  mkdir -p "$TEMP_DIR/$(dirname "$path")"
  echo "$b64" | base64 -d > "$TEMP_DIR/$path" 2>/dev/null || {
    echo "$b64" | base64 -D > "$TEMP_DIR/$path" 2>/dev/null
  }
}

extract 'AGENTS.md' ''
extract 'CLAUDE.md' ''
extract 'agents/claude/agents/code-review-subagent.md' ''
extract 'agents/claude/agents/conductor.md' ''
extract 'agents/claude/agents/documentation-subagent.md' ''
extract 'agents/claude/agents/implement-subagent.md' ''
extract 'agents/claude/agents/planning-subagent.md' ''
extract 'agents/claude/agents/security-subagent.md' ''
extract 'agents/claude/agents/test-subagent.md' ''
extract 'agents/claude/commands/brainstorming.md' ''
extract 'agents/claude/commands/bug-logger.md' ''
extract 'agents/claude/commands/conductor.md' ''
extract 'agents/claude/commands/create-agents-md.md' ''
extract 'agents/claude/commands/excalidraw-diagram.md' ''
extract 'agents/claude/commands/executing-plans.md' ''
extract 'agents/claude/commands/frontend-design.md' ''
extract 'agents/claude/commands/spec-writer.md' ''
extract 'agents/claude/commands/update-docs.md' ''
extract 'agents/claude/commands/using-superpowers.md' ''
extract 'agents/claude/commands/verification-before-completion.md' ''
extract 'agents/claude/commands/webapp-testing.md' ''
extract 'agents/claude/commands/writing-plans.md' ''
extract 'agents/copilot/agents/Conductor.agent.md' ''
extract 'agents/copilot/agents/code-review-subagent.agent.md' ''
extract 'agents/copilot/agents/documentation-subagent.agent.md' ''
extract 'agents/copilot/agents/implement-subagent.agent.md' ''
extract 'agents/copilot/agents/planning-subagent.agent.md' ''
extract 'agents/copilot/agents/security-subagent.agent.md' ''
extract 'agents/copilot/agents/test-subagent.agent.md' ''
extract 'agents/copilot/prompts/brainstorm.md' ''
extract 'agents/copilot/prompts/verify.md' ''
extract 'agents/copilot/prompts/write-plan.md' ''
extract 'agents/copilot/prompts/write-spec.md' ''
extract 'agents/cursor/instructions/conductor-workflow.md' ''
extract 'agents/cursor/rules/code-review.mdc' ''
extract 'agents/cursor/rules/conductor.mdc' ''
extract 'agents/cursor/rules/docs.mdc' ''
extract 'agents/cursor/rules/implement.mdc' ''
extract 'agents/cursor/rules/planning.mdc' ''
extract 'agents/cursor/rules/security-review.mdc' ''
extract 'agents/cursor/rules/test.mdc' ''
extract 'agents/generic/agents/README.md' ''
extract 'agents/generic/workflow.md' ''
extract 'installer/install.ps1' ''
extract 'installer/install.sh' ''
extract 'installer/lib/claude.ps1' ''
extract 'installer/lib/claude.sh' ''
extract 'installer/lib/copilot.ps1' ''
extract 'installer/lib/copilot.sh' ''
extract 'installer/lib/cursor.ps1' ''
extract 'installer/lib/cursor.sh' ''

INSTALLER="$TEMP_DIR/installer/install.sh"
chmod +x "$INSTALLER"
"$INSTALLER" --tool "$TOOL" "$TARGET"
echo "Done! Open your project in your AI tool."
rm -f "$0"
